// Extract SKU from folder name
// Supports Pattern A: /products/{SKU}/ and Pattern B: flat {SKU}_image1.jpg

const items = $input.all();
const results = [];

for (const item of items) {
  const folderName = item.json.name;
  const folderPath = item.json.path_display;

  // Pattern A: Folder name is the SKU
  let sku = folderName.trim().toUpperCase();

  // Check if this looks like a valid SKU (alphanumeric, dashes, underscores)
  const skuPattern = /^[A-Z0-9_-]+$/;

  if (skuPattern.test(sku)) {
    results.push({
      json: {
        sku: sku,
        folder_path: folderPath,
        folder_name: folderName,
        pattern_type: 'A',
        source_tier: 1,
        vendor_id: item.json.vendor_id || $('Start').first().json.vendor_id
      }
    });
  }
}

return results;

// Generate Dropbox download links with dl=1 parameter
// Categorize files into images, videos, and documents

const items = $input.all();
const productData = {};

for (const item of items) {
  const sku = item.json.sku;
  const fileName = item.json.name;
  const filePath = item.json.path_display;

  // Generate shareable link (will need to be converted to direct download)
  // Format: https://www.dropbox.com/s/[id]/[filename]?dl=1
  const baseUrl = 'https://www.dropbox.com';
  const downloadUrl = `${baseUrl}${filePath}?dl=1`;

  if (!productData[sku]) {
    productData[sku] = {
      sku: sku,
      vendor_id: item.json.vendor_id,
      image_urls: [],
      video_urls: [],
      document_urls: [],
      source_tier: 1,
      last_updated: new Date().toISOString()
    };
  }

  // Categorize by file extension
  const ext = fileName.split('.').pop().toLowerCase();
  const imageExts = ['jpg', 'jpeg', 'png', 'gif', 'bmp', 'webp', 'svg'];
  const videoExts = ['mp4', 'mov', 'avi', 'wmv', 'flv', 'webm', 'mkv'];
  const docExts = ['pdf', 'doc', 'docx', 'txt', 'rtf'];

  if (imageExts.includes(ext)) {
    productData[sku].image_urls.push({
      url: downloadUrl,
      filename: fileName,
      type: 'image'
    });
  } else if (videoExts.includes(ext)) {
    productData[sku].video_urls.push({
      url: downloadUrl,
      filename: fileName,
      type: 'video'
    });
  } else if (docExts.includes(ext)) {
    productData[sku].document_urls.push({
      url: downloadUrl,
      filename: fileName,
      type: 'document'
    });
  }
}

// Convert to array
const results = Object.values(productData).map(data => ({ json: data }));

return results;

// Handle Pattern B: Flat structure with {SKU}_filename.ext

const items = $input.all();
const results = [];

for (const item of items) {
  const fileName = item.json.name;
  const filePath = item.json.path_display;

  // Pattern B: Extract SKU from filename (e.g., ABC123_image1.jpg)
  const patternB = /^([A-Z0-9_-]+)_/i;
  const match = fileName.match(patternB);

  if (match) {
    const sku = match[1].toUpperCase();
    const downloadUrl = `https://www.dropbox.com${filePath}?dl=1`;

    results.push({
      json: {
        sku: sku,
        filename: fileName,
        file_path: filePath,
        url: downloadUrl,
        pattern_type: 'B',
        vendor_id: item.json.vendor_id || $('Start').first().json.vendor_id
      }
    });
  }
}

return results;

// Group Pattern B files by SKU

